        "script": {
          "question": "五番：繊維工場の男の人が取引先の女の人と話しています。男の人はこの後、どうしますか。",
          "questionTrans": "（在纺织厂里，男人正在和客户女人交谈。男人接下来要做什么？）",
          "dialogue": [
            {
              "speaker": "男",
              "text": "どうですか。この生地なんですけど。",
              "trans": "（怎么样？这是您要的那种面料。）"
            },
            {
              "speaker": "女",
              "text": "ああ、いいですね。この触り心地はなかなかほかではないんですよね。",
              "trans": "（啊，真不错呢。这种手感在别处可是很难找到的。）"
            },
            {
              "speaker": "男",
              "text": "そうでしょう。うちでは昔からの織り方で作ってるんで、この独特の感じが出るんですよ。",
              "trans": "（是吧。因为我们家是用传统的织法制作的，所以才能呈现出这种独特的感觉。）"
            },
            {
              "speaker": "女",
              "text": "そうですか。<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">①</span>新しいやり方ですと、こうはならないんですか。</span>",
              "trans": "（是吗。如果用新的做法，就做不出这种效果吗？）"
            },
            {
              "speaker": "男",
              "text": "いや、無理ですね。<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">①</span><span class=\"keyword\" onclick=\"showTooltip(event, '男方明确表示用新方法做不到（無理ですね），并且坚持传统做法，因此排除【最新の方法で生地を織る】。')\">手間がかかっても、うちではその点にこだわってますからね。</span></span>",
              "trans": "（不行，做不到呢。哪怕费工夫，我们在这点上也一直很讲究。）"
            },
            {
              "speaker": "女",
              "text": "なるほどね。<span class=\"highlight-correct\"><span class=\"opt-tag tag-correct\">② 🎯 正解キー</span>色合いはかえられますか。</span>",
              "trans": "（原来如此。色调可以调整吗？）"
            },
            {
              "speaker": "男",
              "text": "ご希望をいっていただければ、微妙な違いも出せますよ。",
              "trans": "（如果您提出要求的话，细微的差别也能做出来哦。）"
            },
            {
              "speaker": "女",
              "text": "じゃあ、もう少し、淡い感じを出していただければ、私たちのイメージに合うんですが。",
              "trans": "（那，如果能做得再淡雅一点的话，就符合我们的设想了。）"
            },
            {
              "speaker": "男",
              "text": "<span class=\"highlight-correct\"><span class=\"opt-tag tag-correct\">② 🎯 正解キー</span>ああ、そうですか。わかりました。じゃ、２、３日ください。</span>",
              "trans": "（啊，是吗。明白了。那请给我两三天时间。）"
            },
            {
              "speaker": "女",
              "text": "後、こちらでは、<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">③</span>ふくに仕上げていただくことも可能ですか。</span>",
              "trans": "（还有，请问你们这边也能帮我们做成衣服吗？）"
            },
            {
              "speaker": "男",
              "text": "うん、ちょっと時間かかりますね。<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">④</span><span class=\"keyword\" onclick=\"showTooltip(event, '男方只是陈述当前“人手不足”的严峻现状作为拒绝做衣服的理由，并没有说要去【人手を増やす】（增加人手），因此排除。')\">今、人手が足りないんですよ。</span>厳しくてね。</span>",
              "trans": "（嗯，那得花点时间呢。现在人手不足。情况比较严峻。）"
            },
            {
              "speaker": "女",
              "text": "ああ、そうですか。<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">③</span><span class=\"keyword\" onclick=\"showTooltip(event, '女方听到男方人手不足后，表示“那很难办呢”，放弃了让男方做衣服的请求，因此排除【生地から服を作る】。')\">それですと、難しいですね。</span></span>",
              "trans": "（啊，是吗。那样的话，就很难办了呢。）"
            },
            {
              "speaker": "男",
              "text": "すみません。じゃ、ご希望に合うようにやってみます。",
              "trans": "（不好意思。那，我会试着做出符合您要求的面料的。）"
            },
            {
              "speaker": "女",
              "text": "はい、お願いします。",
              "trans": "（好的，拜托了。）"
            }
          ]
        },
