        "audio": "file:///Users/kiki/Desktop/ki%E8%AE%A1%E5%88%92/exam/listening/task-comprehension/n1/assets/audio/2011.7-2.mp3",
        "image": "",
        "dialogueHtml": "",
        "translation": "",
        "script": {
          "question": "二番：女の人と男の人が話しています。女の人はどうしますか？",
          "questionTrans": "（女人和男人在交谈。女人接下来会怎么做？）",
          "dialogue": [
            {
              "speaker": "女",
              "text": "部屋の観葉植物、なんか元気ないんだあ。",
              "trans": "（房间里的观叶植物，总感觉没什么精神啊。）"
            },
            {
              "speaker": "男",
              "text": "えっ、ちゃんと水やってる？",
              "trans": "（哎？有好好浇水吗？）"
            },
            {
              "speaker": "女",
              "text": "それが、すぐ忘れちゃって、気がついたら、<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">①</span><span class=\"explain-wrong\" onclick=\"showTooltip(event, '女生只是说因为忘记浇水导致【土干透了（土がからから）】，并没有说要【换土（土を換える）】，因此排除。')\">土がからからってことよくあるんだ。</span></span>",
              "trans": "（那个嘛，我老是忘，等回过神来的时候，土经常都干透了。）"
            },
            {
              "speaker": "男",
              "text": "あのさ、この前ニュースでやってたんだけど、<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">②</span><span class=\"explain-wrong\" onclick=\"showTooltip(event, '调查牛的产奶情况是【某大学的研究（ある大学の研究で）】，是在新闻里听说的，而不是女生接下来要做的事，因此排除。')\">ある大学の研究で、名前を付けて育てた牛と、名前がないまま育てた牛のミルクの出方を調べたら</span></span>、そしたら、名前を付けた方がミルクの出方がよかったんだって。",
              "trans": "（那个啊，前阵子新闻上播过，某大学的一项研究调查了起了名字养的牛和没起名字养的牛的产奶情况，结果发现起了名字的牛产奶量更高。）"
            },
            {
              "speaker": "女",
              "text": "は？",
              "trans": "（哈？）"
            },
            {
              "speaker": "男",
              "text": "名前を付ければ愛着が増して、いろいろ世話をするようになるからって。そうすると、牛のストレスが減って、ミルクの出方もよくなったってわけ。",
              "trans": "（说是起了名字的话就会产生感情，照顾起来也会更用心。那样一来，牛的压力减少了，产奶量也就变好了。）"
            },
            {
              "speaker": "女",
              "text": "ふーん。",
              "trans": "（嗯……）"
            },
            {
              "speaker": "男",
              "text": "だから、君もやってみたら？",
              "trans": "（所以，你要不要也试试？）"
            },
            {
              "speaker": "女",
              "text": "えっ、<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">③</span><span class=\"explain-wrong\" onclick=\"showTooltip(event, '女生误以为男生建议她去养牛并【给牛起名字】，这只是个误会的玩笑，被男生立刻纠正了，因此排除。')\">牛を飼うの？</span></span>",
              "trans": "（哎？养牛吗？）"
            },
            {
              "speaker": "男",
              "text": "<span class=\"highlight-correct\"><span class=\"opt-tag tag-correct\">④ 🎯 正解キー</span>名前だよ。すぐ忘れちゃうんでしょ。水やるの。</span>",
              "trans": "（是起名字啦。你不是老忘吗？浇水这事儿。）"
            },
            {
              "speaker": "女",
              "text": "あーあ、牛と植物は違う気もするけど、面白いね。<span class=\"highlight-correct\"><span class=\"opt-tag tag-correct\">④ 🎯 正解キー</span>やってみよう。</span>",
              "trans": "（啊，虽然我觉得牛和植物好像不太一样，不过挺有意思的。我试试吧。）"
            }
          ]
        },
        "options": [
          {
            "text": "植物の土を換える",
            "translation": "（给植物换土）",
            "correct": false
          },
          {
            "text": "牛のミルクの出方を調べる",
            "translation": "（调查牛的产奶情况）",
            "correct": false
          },
          {
            "text": "牛に名前をつける",
            "translation": "（给牛起名字）",
            "correct": false
          },
          {
            "text": "植物に名前をつける",
            "translation": "（给植物起名字）",
            "correct": true
          }
        ]
