        "image": "",
        "dialogueHtml": "",
        "translation": "",
        "script": {
          "question": "",
          "questionTrans": "",
          "dialogue": [
            {
              "speaker": "女",
              "text": "はい、富士出版です。",
              "trans": "（您好，这里是富士出版。）"
            },
            {
              "speaker": "男",
              "text": "お世話になっております。桜印刷の山川ですが、田中さんはいらっしゃいますか。",
              "trans": "（您好，我是樱花印刷的山川。请问田中先生在吗？）"
            },
            {
              "speaker": "女",
              "text": "お世話になっております。あいにく田中は席をはずしておりまして、２時からミーティングがあるので、その前には戻る予定ですが。",
              "trans": "（您好。很不凑巧，田中现在不在座位上。他2点有个会议，预计会在那之前回来。）"
            },
            {
              "speaker": "男",
              "text": "そうですか。実は先ほど、私が留守の間、田中さんからお電話をいただいたようで、<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">①②</span><span class=\"explain-wrong\" onclick=\"showTooltip(event, '男人只是提到田中的留言是【关于明天会议的事情（明日の会議の件だ）】，并没有提到会议时间更改或要求出席，排除。')\">明日の会議の件だと伝言があったんですが。</span></span>",
              "trans": "（这样啊。其实是刚才我不在的时候，田中先生好像给我打过电话，并留了言说是关于明天会议的事情。）"
            },
            {
              "speaker": "女",
              "text": "そうですか。では、<span class=\"highlight-correct\"><span class=\"opt-tag tag-correct\">③</span>田中が戻り次第、山川さんに<span class=\"keyword\" onclick=\"showTooltip(event, '折（お）り返（かえ）し：回复，回电。')\">折り返し</span>お電話差し上げるよう伝えましょうか。</span>",
              "trans": "（原来如此。那等田中一回来，我就转告他给您回个电话吧？）"
            },
            {
              "speaker": "男",
              "text": "<span class=\"highlight-wrong\"><span class=\"opt-tag tag-wrong\">④</span><span class=\"explain-wrong\" onclick=\"showTooltip(event, '男人回答【拜托您了（お願いできますか）】，同意了让田中给对方回电的提议，而不是山川自己再打过来，排除。')\">お願いできますか。</span></span>",
              "trans": "（那就拜托您了。）"
            },
            {
              "speaker": "女",
              "text": "はい、かしこまりました。",
              "trans": "（好的，明白了。）"
            }
          ]
        },
        "options": [
          {
            "text": "田中さんへ 会議の時間が変わりました",
            "translation": "（给田中：会议的时间改变了）",
            "correct": false,
            "explanation": ""
          },
          {
            "text": "田中さんへ 明日の会議に出席してください",
            "translation": "（给田中：请出席明天的会议）",
            "correct": false,
            "explanation": ""
          },
          {
            "text": "田中さんへ サクラ印刷の山川さんに電話してください",
            "translation": "（给田中：请给樱花印刷的山川先生回电话）",
            "correct": true,
            "explanation": ""
          },
          {
            "text": "田中さんへ サクラ印刷の山川さんが再度電話をくださいます",
            "translation": "（给田中：樱花印刷的山川先生会再打来电话）",
            "correct": false,
            "explanation": ""
          }
        ]
